#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int total = N - 111 + 1;
        int a = N / 222;
        int b = N / 333;
        int c = N / 555;
        int ab = N / 666;   // lcm(222,333)
        int ac = N / 1110;  // lcm(222,555)
        int bc = N / 1665;  // lcm(333,555)
        int abc = N / 3330; // lcm of all three
        int unionCnt = a + b + c - (ab + ac + bc) + abc;
        int ans = total - unionCnt;
        printf("%d\n", ans);
    }
    return 0;
}

